// ============================================================
// Samsic Planning IA - Seed Data
// Realistic Luxembourg demo data (French names, local context)
//
// IMPORTANT: All date-dependent data is generated by factory functions
// (generateSeedAbsences, generateSeedAffectations, generateSeedAlerts)
// so that every cold start in serverless produces dates relative to
// the *current* day, not the day the module was first imported.
// ============================================================

import type {
  Employee,
  Client,
  Affectation,
  Absence,
  Alert,
} from './types';

// --- Date helpers (called at generation time, never cached) ---

function today(): string {
  return new Date().toISOString().split('T')[0];
}

function weekday(offsetFromMonday: number): string {
  const now = new Date();
  const dayOfWeek = now.getDay(); // 0=Sun, 1=Mon...
  const monday = new Date(now);
  monday.setDate(now.getDate() - (dayOfWeek === 0 ? 6 : dayOfWeek - 1));
  const target = new Date(monday);
  target.setDate(monday.getDate() + offsetFromMonday);
  return target.toISOString().split('T')[0];
}

/** Returns the day-of-week offset (0=Mon ... 4=Fri) for today, clamped to weekdays. */
function todayWeekdayOffset(): number {
  const dow = new Date().getDay(); // 0=Sun, 1=Mon ... 6=Sat
  if (dow === 0) return 4; // Sunday -> treat as Friday for demo
  if (dow === 6) return 4; // Saturday -> treat as Friday for demo
  return dow - 1; // Mon=0, Tue=1 ... Fri=4
}

