// ============================================================
// AFFECTATIONS (current week) - generated dynamically
//
// Story: Each titulaire is assigned Mon-Fri at their client.
// Formation and stand_by assignments fill out the week.
// ============================================================

export function generateSeedAffectations(): Affectation[] {
  const todayOffset = todayWeekdayOffset();

  // Titulaire assignments: each of the 6 clients' titulaire works Mon-Fri
  const titulairePairs: [string, string][] = [
    ['emp-003', 'cli-001'], // Julie Weber -> Banque Fortuna
    ['emp-004', 'cli-002'], // Sophie Muller -> Cabinet Albers
    ['emp-001', 'cli-003'], // Marie Schmit -> Hotel Le Royal
    ['emp-005', 'cli-004'], // Chantal Thill -> Assurances Foyer
    ['emp-013', 'cli-005'], // Diane Schiltz -> Ministere des Finances
    ['emp-009', 'cli-006'], // Laura Hoffmann -> Clinique Bohler
  ];

  const affectations: Affectation[] = [];

  for (const [empId, clientId] of titulairePairs) {
    for (let day = 0; day < 5; day++) {
      affectations.push({
        id: `aff-${clientId.replace('cli-', '')}-${day + 1}`,
        employe_id: empId,
        client_id: clientId,
        date: weekday(day),
        type: 'titulaire',
        statut: 'confirme',
        created_at: '2026-03-01T08:00:00Z',
      });
    }
  }

  // Formation: emp-007 (Nathalie Klein) training at Banque Fortuna Mon+Tue
  affectations.push(
    {
      id: 'aff-form-001',
      employe_id: 'emp-007',
      client_id: 'cli-001',
      date: weekday(0),
      type: 'formation',
      statut: 'confirme',
      created_at: '2026-03-01T08:00:00Z',
    },
    {
      id: 'aff-form-002',
      employe_id: 'emp-007',
      client_id: 'cli-001',
      date: weekday(1),
      type: 'formation',
      statut: 'confirme',
      created_at: '2026-03-01T08:00:00Z',
    },
  );

  // Formation: emp-014 (Lucia Rodrigues) training at Hotel Le Royal on Wednesday
  affectations.push({
    id: 'aff-form-003',
    employe_id: 'emp-014',
    client_id: 'cli-003',
    date: weekday(2),
    type: 'formation',
    statut: 'confirme',
    created_at: '2026-03-01T08:00:00Z',
  });

  // Formation: emp-002 (Ana Ferreira) training at Clinique Bohler on Thursday
  affectations.push({
    id: 'aff-form-004',
    employe_id: 'emp-002',
    client_id: 'cli-006',
    date: weekday(3),
    type: 'formation',
    statut: 'confirme',
    created_at: '2026-03-01T08:00:00Z',
  });

  // Formation: emp-015 (Thomas Wagner) training at Ministere on Tuesday
  affectations.push({
    id: 'aff-form-005',
    employe_id: 'emp-015',
    client_id: 'cli-005',
    date: weekday(1),
    type: 'formation',
    statut: 'confirme',
    created_at: '2026-03-01T08:00:00Z',
  });

  // Stand-by: emp-006 (Carlos) covers Assurances Foyer on Wednesday
  affectations.push({
    id: 'aff-sb-001',
    employe_id: 'emp-006',
    client_id: 'cli-004',
    date: weekday(2),
    type: 'stand_by',
    statut: 'confirme',
    created_at: '2026-03-01T08:00:00Z',
  });

  // Stand-by: emp-010 (Sandra) covers Hotel Le Royal on Friday
  affectations.push({
    id: 'aff-sb-002',
    employe_id: 'emp-010',
    client_id: 'cli-003',
    date: weekday(4),
    type: 'stand_by',
    statut: 'confirme',
    created_at: '2026-03-01T08:00:00Z',
  });

  return affectations;
}

// ============================================================
// ABSENCES - generated dynamically so "today" is always current
//
// Story for the demo:
// 1. Julie Weber (titulaire Banque Fortuna) is sick today -> urgent, uncovered
// 2. Sophie Muller (titulaire Cabinet Albers) has an unplanned absence today -> urgent, uncovered
// 3. Diane Schiltz (titulaire Min. Finances) has a planned leave on Thursday -> upcoming, uncovered
// This gives the dashboard 2 absences today (both uncovered) + 1 upcoming.
// ============================================================

export function generateSeedAbsences(): Absence[] {
  const todayStr = today();
  const nowIso = new Date().toISOString();

  return [
    {
      id: 'abs-001',
      employe_id: 'emp-003',
      client_id: 'cli-001',
      date: todayStr,
      type: 'maladie',
      channel: 'telephone',
      statut: 'ouverte',
      notes: 'Grippe, certificat médical à fournir sous 48h.',
      created_at: nowIso,
    },
    {
      id: 'abs-002',
      employe_id: 'emp-004',
      client_id: 'cli-002',
      date: todayStr,
      type: 'imprevue',
      channel: 'whatsapp',
      statut: 'ouverte',
      notes: 'Problème familial urgent, absence signalée à 7h15 ce matin.',
      created_at: nowIso,
    },
    {
      id: 'abs-003',
      employe_id: 'emp-013',
      client_id: 'cli-005',
      date: weekday(3), // Thursday
      type: 'conge',
      channel: 'email',
      statut: 'ouverte',
      notes: 'Congé personnel validé par la direction.',
      created_at: new Date(Date.now() - 2 * 24 * 60 * 60 * 1000).toISOString(),
    },
  ];
}

